import{_ as e,o as a,c as o,O as r}from"./chunks/framework.bdcb0ee1.js";const m=JSON.parse('{"title":"Your Profile","description":"","frontmatter":{},"headers":[],"relativePath":"userguide/profile.md","filePath":"userguide/profile.md","lastUpdated":1773167796000}'),i={name:"userguide/profile.md"},t=r('<h1 id="your-profile" tabindex="-1">Your Profile <a class="header-anchor" href="#your-profile" aria-label="Permalink to &quot;Your Profile&quot;">​</a></h1><p>Your profile is your public identity on the board. It displays your posts, achievements and account information.</p><nav class="table-of-contents"><ul><li><a href="#viewing-your-profile">Viewing your profile</a></li><li><a href="#editing-your-profile">Editing your profile</a></li><li><a href="#custom-profile-fields">Custom profile fields</a></li><li><a href="#avatar">Avatar</a></li><li><a href="#achievements">Achievements</a></li><li><a href="#name-changes">Name changes</a></li></ul></nav><h2 id="viewing-your-profile" tabindex="-1">Viewing your profile <a class="header-anchor" href="#viewing-your-profile" aria-label="Permalink to &quot;Viewing your profile&quot;">​</a></h2><p>Click your username or avatar in the navigation bar and select <strong>Profile</strong> to view your public profile page. Other members can also view your profile by clicking your name on any of your posts.</p><p>Your profile shows:</p><ul><li>Your avatar and username</li><li>Post and topic count</li><li>Member number and registration date</li><li>Showcased achievements</li><li>Custom profile fields</li></ul><h2 id="editing-your-profile" tabindex="-1">Editing your profile <a class="header-anchor" href="#editing-your-profile" aria-label="Permalink to &quot;Editing your profile&quot;">​</a></h2><p>Navigate to <strong>Edit Profile</strong> from the user menu to update your information. The following fields can be changed:</p><ul><li><strong>Email</strong> — updating your email requires re-verification.</li><li><strong>Avatar</strong> — upload a custom avatar image. If you do not upload one, a default avatar is generated for you.</li><li><strong>Signature</strong> — a short piece of text or BBCode that appears below all your posts.</li><li><strong>Location</strong> — your displayed location.</li><li><strong>Date of Birth</strong> — you can choose to hide your birthday or your age from other members using the privacy toggles.</li><li><strong>Custom User Title</strong> — override the title assigned by your user group with a personal title.</li><li><strong>Timezone</strong> — set your timezone so that timestamps are displayed in your local time.</li><li><strong>Dark Mode</strong> — toggle between light and dark themes.</li></ul><img width="1937" height="1551" alt="image" src="https://github.com/user-attachments/assets/f5a6bb27-8656-42fe-8614-c391c3b2e0db"><h2 id="custom-profile-fields" tabindex="-1">Custom profile fields <a class="header-anchor" href="#custom-profile-fields" aria-label="Permalink to &quot;Custom profile fields&quot;">​</a></h2><p>Your board administrator may have created additional profile fields. These appear on the edit profile page alongside the standard fields. Fill them in to share more about yourself — some fields may be displayed next to your posts in the mini profile area.</p><h2 id="avatar" tabindex="-1">Avatar <a class="header-anchor" href="#avatar" aria-label="Permalink to &quot;Avatar&quot;">​</a></h2><p>Upload a custom avatar from the edit profile page. To remove your avatar and revert to the default, use the <strong>Delete Avatar</strong> option.</p><h2 id="achievements" tabindex="-1">Achievements <a class="header-anchor" href="#achievements" aria-label="Permalink to &quot;Achievements&quot;">​</a></h2><p>If your board has achievements enabled, you can view your earned and locked achievements from your profile page. Toggle the <strong>Showcase</strong> option on any earned achievement to display it prominently on your profile.</p><img width="2080" height="1883" alt="image" src="https://github.com/user-attachments/assets/73d5a6d7-67e8-4955-8cb6-bf7764015060"><h2 id="name-changes" tabindex="-1">Name changes <a class="header-anchor" href="#name-changes" aria-label="Permalink to &quot;Name changes&quot;">​</a></h2><p>If your board supports name changes, you can request a new username from your profile. Provide your desired username and a reason for the change. An administrator will review and approve or deny your request.</p>',20),l=[t];function n(s,u,d,h,p,f){return a(),o("div",null,l)}const g=e(i,[["render",n]]);export{m as __pageData,g as default};
